#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, a;
        scanf("%d %d", &n, &a);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        int count = 0;
        for (int i = 0; i < n; i++) {
            count += (arr[i] > a) ? arr[i] - a : a - arr[i];
        }
        printf("%d\n", count);
    }
    return 0;
}

